async (params, browser) => {
  // Open Goodreads
  await browser.open(`https://www.goodreads.com/author/show/${params.author_id}`)

  // Wait for page
  await browser.waitForSelector('h1, .authorName, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1, .authorName')?.textContent?.trim() || ''; const bioEl = document.querySelector('[data-testid="aboutAuthor"], [class*="AboutAuthor"] [class*="Formatted"], .aboutAuthorInfo span, [class*="DetailsLayoutRightParagraph"]'); const bio = bioEl?.textContent?.trim()?.slice(0, 500) || ''; const books = []; document.querySelectorAll('a.bookTitle, [class*="book"] a[href*="/book/show/"], a[href*="/book/show/"]').forEach((b, i) => { if (i < 10) books.push({ title: b.textContent?.trim(), url: b.href || '' }); }); const img = document.querySelector('.authorPhoto img, img[alt*="author"], [class*="AuthorPhoto"] img')?.src || ''; return { name, bio, books, image: img, url: window.location.href };`)

  return result
}
